// ابحث في كل الـ rows مش أول واحدة بس
const rows = $input.all();

let result = null;

for (const item of rows) {
  const row = item.json;

  for (let i = 1; i <= 8; i++) {
    const val = (row[`حصه ${i}`] || '').trim();
    if (val === 'post') {
      result = {
        grop_id: row.grop_id,
        lecture_num: i,
        url: row[`url_${i}`] || row['url'] || '',
        title: row.note || `حصه ${i}`
      };
      break;
    }
  }

  if (result) break;
}

if (!result) {
  return [];
}

return [{ json: result }];

// جهّز بيانات الحضور - اكتب في الكولومن الصح
const query = $('Webhook: تسجيل الحضور1').first().json.query;

const lectureNum = query.lecture_num || '1';
const columnName = 'حصة ' + lectureNum;

return [{
  json: {
    'chat id': query.student_id,
    [columnName]: 'حضر',
    'Student Name':$input.first().json['Student Name']
  }
}];

// ابني اللنكات مع lecture_num
const lecture = $('حدد الحصة المتغيرة').first().json;
const students = $input.all();
const baseUrl = 'https://alisaadeng-n8n.hf.space/webhook/lecture-track';

return students.map(s => {
  const student = s.json;

  const trackUrl = baseUrl
    + '?student_id=' + encodeURIComponent(student['chat id'] || '')
    + '&student_name=' + encodeURIComponent(student['Student Name'] || '')
    + '&lecture_id=' + encodeURIComponent(lecture.grop_id || '')
    + '&lecture_num=' + encodeURIComponent(lecture.lecture_num || '1')
    + '&lecture_title=' + encodeURIComponent(lecture.title || '')
    + '&url=' + encodeURIComponent(lecture.url || '');

  return {
    json: {
      chat_id: student['chat id'],
      full_name: student['Student Name'],
      lecture_id: lecture.grop_id,
      lecture_num: lecture.lecture_num,
      lecture_title: lecture.title,
      tracking_url: trackUrl
    }
  };
});

const lecture = $('ابني اللنكات1').first().json;
const lectureNum = lecture.lecture_num;
const columnName = 'حصه ' + lectureNum;

return [{
  json: {
    grop_id: lecture.lecture_id,
    [columnName]: 'posted'
  }
}];

const body = $input.first().json.body;

const columnName = body.lesson_code;

// استخراج رقم الحصة وتكوين الاسم
const lessonNumber = parseInt(columnName.split('_').pop().replace('L', ''));
const lessonKey = `lesson_${lessonNumber}`;

return [{
  json: {
    'chat id': String(body.student_id),
    'student_name': body.student_name,
    [lessonKey]: `${body.score}/${body.total_points}`,

  }
}];
